    color: color,
    textAlign: 'center',
    margin: '4px 0 4px 0',
    padding: '0',
    width: TOTAL_W + 'px'
  });

  var bar = ui.Panel({
    widgets: [
      ui.Label('', {
        backgroundColor: color,
        width: fillW + 'px',
        height: '8px',
        margin: '0',
        padding: '0'
